INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (5, 'claim_extraction_comprehensive_no_topics', 'user', 'TASKS\n1) Extract DISTINCT factual claims from the text ONLY.\n   - Return AT LEAST {{minClaims}} and AT MOST {{maxClaims}} claims, if available.\n   - Each claim must be independently verifiable, one atomic assertion per item.\n   - Each claim must be SELF-CONTAINED: resolve pronouns, include context (time/place/subject).\n   - Prefer claims with numbers, dates, named entities, locations, or concrete actions.\n   - Avoid duplicates, paraphrases, opinions, or vague summaries.\n   - Phrase each claim as a full sentence.\n   - Example: "Trump won 2016 US election" NOT "He won the election"\n\n2) Do NOT invent topics or testimonials in this mode.', '{"maxClaims":12,"minClaims":5}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (4, 'claim_extraction_comprehensive_with_topics', 'user', 'TASKS\n1) Identify the single most general topic (max 2 words).\n2) List 2–5 specific subtopics under that topic.\n3) Extract DISTINCT factual claims from the text.\n   - Return AT LEAST {{minClaims}} and AT MOST {{maxClaims}} claims, if available.\n   - Each claim must be independently verifiable, one atomic assertion per item.\n   - Each claim must be SELF-CONTAINED: resolve pronouns, include context (time/place/subject).\n   - Prefer claims with numbers, dates, named entities, locations, or concrete actions.\n   - Avoid duplicates, paraphrases, opinions, or vague summaries.\n   - Phrase each claim as a full sentence.\n   - Example: "Trump won 2016 US election" NOT "He won the election"\n\n4) Extract any testimonials/first-person case studies if present (objects with "text", optional "name", optional "imageUrl").\n   - Deduplicate against the main text if overlapping.', '{"maxClaims":12,"minClaims":5}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (203, 'claim_extraction_edge_for_source_system', 'system', 'You are extracting claims from an evidence source to evaluate a specific case claim. Extract claims that DIRECTLY ADDRESS the case claim using SIMILAR TERMINOLOGY and FRAMING. You must return strictly valid JSON.', '{}', 5, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (204, 'claim_extraction_edge_for_source_user', 'user', 'CASE CLAIM BEING INVESTIGATED:\n"{{caseClaimText}}"\n\nCASE CLAIM THEME: {{caseClaimTheme}}\n\nEVIDENCE SOURCE TEXT:\n{{sourceText}}\n\nTASK: Extract {{minClaims}}-{{maxClaims}} claims that DIRECTLY ADDRESS the case claim.\n\nCRITICAL REQUIREMENTS:\n\n1. TOPICAL ALIGNMENT: Only extract claims about the SAME SUBJECT as the case claim\n   - If case claim is about "mRNA vaccine adverse events" → Extract claims about mRNA vaccine safety/harm\n   - If case claim is about "2020 election fraud" → Extract claims about 2020 election integrity\n   - SKIP claims about related but different topics\n\n2. LANGUAGE MIRRORING: Frame claims using SIMILAR TERMINOLOGY to the case claim\n   - If case claim says "adverse events" → Use "adverse events" not "side effects"\n   - If case claim says "ballot harvesting" → Use "ballot harvesting" not "voter fraud"  \n   - If case claim uses specific names/dates → Reference the same names/dates when relevant\n   \n3. RELATIONSHIP CLARITY: Each claim should be obviously FOR, AGAINST, or NUANCING the case claim\n   \n   ✅ GOOD (relationship is clear):\n   Case: "mRNA vaccines caused 1 in 800 serious adverse events"\n   Source: "FDA analysis found mRNA vaccine serious adverse event rate of 1 in 5000"\n   → Instantly recognizable as refuting (different rate)\n   \n   Source: "Pfizer trial data showed serious adverse events in 1.2% of vaccinated participants"  \n   → Instantly recognizable as supporting (1.2% ≈ 1 in 800)\n   \n   ❌ BAD (relationship is unclear):\n   Source: "Some people had reactions to vaccines"\n   → Too vague, unclear if this addresses the 1 in 800 rate\n   \n   Source: "Dr. Smith raised concerns about vaccine safety in 2021"\n   → Doesn''t specify what concerns or provide comparable data\n\n4. ATOMIC & SPECIFIC: Each claim must be:\n   - ONE falsifiable assertion\n   - Self-contained with full context\n   - Include specific numbers, dates, sources when comparing to case claim\n\nEXTRACTION PRIORITY:\na) Claims with DATA that directly confirms/refutes the case claim (same metrics, comparable populations)\nb) Claims with CONTEXT that explains why the case claim might be true/false\nc) Claims with ALTERNATIVE INTERPRETATIONS of the same evidence\nd) Claims with HISTORICAL PRECEDENT relevant to evaluating the case claim\n\nReturn claims in order of relevance to the case claim.', '{"maxClaims":9,"minClaims":3}', 5, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (410, 'claim_extraction_edge_no_topics', 'user', 'TASKS\n1) Extract the {{minClaims}}-{{maxClaims}} SHARPEST, most impactful verifiable claims from the text.\n\n   EDGE MODE - be ruthless. Only extract claims that meet ALL of:\n   a) SPECIFICITY: concrete numbers, dates, named entities, or clearly falsifiable assertions\n   b) CONTROVERSY: genuinely disputed, surprising, or counterintuitive\n   c) MATERIALITY: central to the article main argument or thesis\n\n   CRITICAL: Extract ATOMIC claims - break compound statements into separate claims.\n\n   REQUIREMENTS:\n   - Each claim must be FALSIFIABLE: can be proven true or false with evidence\n   - Each claim must be SELF-CONTAINED: resolve pronouns, include full context (time/place/subject/numbers)\n   - Phrase each claim as a complete, specific sentence\n   - Return only the top {{maxClaims}} highest-impact claims\n\n2) Do NOT invent topics or testimonials in this mode.', '{"maxClaims":7,"minClaims":3}', 6, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (408, 'claim_extraction_edge_system', 'system', 'You are a precise claim extraction assistant. You must return strictly valid JSON.', '{}', 7, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (409, 'claim_extraction_edge_with_topics', 'user', 'TASKS\n1) Identify the single most general topic (max 2 words).\n2) List 2-5 specific subtopics under that topic.\n3) Extract the {{minClaims}}-{{maxClaims}} SHARPEST, most impactful verifiable claims from the text.\n\n   EDGE MODE - be ruthless. Only extract claims that meet ALL of:\n   a) SPECIFICITY: concrete numbers, dates, named entities, or clearly falsifiable assertions\n   b) CONTROVERSY: genuinely disputed, surprising, or counterintuitive\n   c) MATERIALITY: central to the article main argument or thesis\n\n   CRITICAL: Extract ATOMIC claims - break compound statements into separate claims:\n   - Study findings (what the study found, with specifics)\n   - Comparative claims (X compared to Y, X higher/lower than Y)\n   - Causal claims (X caused Y)\n   - Historical precedents (past events, previous decisions)\n   - Expert opinions/statements with concrete content\n\n   REQUIREMENTS:\n   - Each claim must be FALSIFIABLE: can be proven true or false with evidence\n   - Each claim must be SELF-CONTAINED: resolve pronouns, include full context (time/place/subject/numbers)\n   - Phrase each claim as a complete, specific sentence\n   - Return only the top {{maxClaims}} highest-impact claims\n\n4) Extract any testimonials/first-person case studies if present (objects with "text", optional "name", optional "imageUrl").', '{"maxClaims":7,"minClaims":3}', 6, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (406, 'claim_extraction_ranked_no_topics', 'user', 'TASKS\n\nExtract {{minClaims}}-{{maxClaims}} IMPORTANT, VERIFIABLE claims from the text.\n\nPRIMARY GOAL\n\nExtract the most important real-world claims made in the text.\n\nDo NOT extract claims about the article itself.\n\nYour job is not to prove that the article said something.\nYour job is to extract the factual claims, allegations, findings, and interpretations that the article asks the reader to believe.\n\nCRITICAL DISTINCTION: EXTRACT WORLD-CLAIMS, NOT ARTICLE-CLAIMS\n\nDo NOT write claims in this form:\n- "The article says..."\n- "The article reports..."\n- "The author argues..."\n- "The text claims..."\n- "According to the article..."\n- "KUOW reports..."\n- "The article suggests..."\n\nUnless the attribution itself is the thing being fact-checked.\n\nInstead, convert article statements into direct, testable real-world claims.\n\nBAD:\n"The article reports that Viewlands Elementary principal Frank Brouillet placed a second-grade boy in an enclosure known as ''the cage'' multiple times during the school day."\n\nGOOD:\n"Viewlands Elementary principal Frank Brouillet placed a second-grade boy in an enclosure known as ''the cage'' multiple times during the school day."\n\nBAD:\n"The article argues that Seattle Public Schools failed to protect a student."\n\nGOOD:\n"Seattle Public Schools failed to protect a second-grade boy at Viewlands Elementary from repeated placement in an enclosure known as ''the cage.''"\n\nBAD:\n"KUOW says the enclosure was called ''the cage.''"\n\nGOOD:\n"An enclosure used for a second-grade boy at Viewlands Elementary was known as ''the cage.''"\n\nUse attribution only when the source of the claim is itself part of the real-world claim.\n\nGOOD:\n"Seattle Public Schools investigators found that a second-grade boy at Viewlands Elementary was placed in an enclosure known as ''the cage'' multiple times during the school day."\n\nARTICLE-SPECIFICITY REQUIREMENT\n\nThe output must NOT genericize the article.\n\nA good claim should preserve the article’s unique identifying details whenever present:\n- named people\n- named institutions\n- named schools, agencies, companies, courts, studies, reports, or organizations\n- city, state, country, or region\n- dates or time periods\n- quoted terms or disputed labels\n- specific actions\n- specific findings\n- specific allegations\n- specific conclusions\n- affected people or groups\n\nIf the article names a person, institution, place, report, study, agency, official, or organization, include those names in the relevant claims.\n\nIf the article uses a distinctive or contested phrase, preserve it in quotation marks.\n\nExamples of distinctive or contested phrases:\n- "the cage"\n- "locked in"\n- "seclusion"\n- "restraint"\n- "outside enclosure"\n- "investigation found"\n- "cleared of wrongdoing"\n- "policy violation"\n- "misleading"\n- "abuse"\n- "cover-up"\n\nDo NOT replace specific language with generic language.\n\nBAD:\n"A school district used controversial discipline practices."\n\nGOOD:\n"Viewlands Elementary principal Frank Brouillet placed a second-grade boy in an enclosure known as ''the cage'' multiple times during the school day."\n\nBAD:\n"An investigation found misconduct at a school."\n\nGOOD:\n"Seattle Public Schools investigators found that a second-grade boy at Viewlands Elementary was placed in an enclosure known as ''the cage'' multiple times during the school day."\n\nCLAIM TYPES TO PRIORITIZE\n\nExtract a mix of these claim types, ranked by importance:\n\nA) CENTRAL REAL-WORLD THESIS CLAIM, REQUIRED AS FIRST CLAIM\n- The first claim must capture the article’s central factual allegation, finding, conclusion, or argument.\n- It must be a direct claim about reality, not a meta-claim about the article.\n- It must include the key named entities, locations, institutions, and distinctive wording when present.\n- It may synthesize the article’s main point, but it must remain specific, evidence-checkable, and searchable.\n\nB) CENTRAL EVENT OR ALLEGATION CLAIMS\n- Claims describing the central event, allegation, accusation, finding, or dispute.\n- Include who did what, to whom, where, when, and under what claimed circumstances.\n- Preserve charged or disputed language when it is central to the article.\n\nC) OFFICIAL FINDING OR DOCUMENT CLAIMS\n- Investigation findings\n- Court findings\n- Agency findings\n- School district findings\n- Police reports\n- Medical or scientific findings\n- Published study findings\n- Policy or disciplinary findings\n\nD) FRAMING OR INTERPRETIVE CLAIMS\n- Claims about whether an event constituted abuse, misconduct, negligence, exoneration, policy failure, institutional wrongdoing, discrimination, risk, or safety failure.\n- These are valid only when grounded in the text.\n- Phrase them as real-world claims, not as claims about the article’s framing.\n\nBAD:\n"The article frames the enclosure as a disciplinary seclusion space."\n\nGOOD:\n"The enclosure known as ''the cage'' functioned as a disciplinary seclusion space for the second-grade boy at Viewlands Elementary."\n\nE) ATOMIC SUPPORTING CLAIMS\n- Concrete details that can be verified independently.\n- Break compound statements into separate claims when doing so improves verification.\n- Preserve enough context so each claim stands alone.\n\nRANKING CRITERIA\n\nPrioritize in this order:\n\n1. Centrality: The claim is necessary to understand the article’s main point.\n2. Identifiability: The claim includes enough names, places, institutions, and wording to identify the same incident, report, study, or dispute.\n3. Controversy: The claim is disputed, high-stakes, surprising, reputationally significant, or central to the conflict.\n4. Falsifiability: The claim can be supported, refuted, or nuanced with evidence.\n5. Search usefulness: The claim would produce relevant search results instead of unrelated articles.\n6. Specificity: The claim contains concrete details where available.\n\nIMPORTANT: DO NOT CHOOSE BROADNESS OVER IDENTIFIABILITY\n\nA broader claim is only better if it still includes the specific people, institutions, locations, and disputed wording needed to identify the article.\n\nBAD BROAD THESIS:\n"School discipline policies can harm vulnerable students."\n\nGOOD ARTICLE-SPECIFIC THESIS:\n"Seattle Public Schools failed to protect a second-grade boy at Viewlands Elementary from repeated placement in an enclosure known as ''the cage.''"\n\nPRESERVE CHARGED OR CONTESTED LANGUAGE\n\nIf the text uses charged language such as:\n- "locked in a cage"\n- "the cage"\n- "abuse"\n- "seclusion"\n- "restraint"\n- "cover-up"\n- "exonerated"\n- "falsely accused"\n- "misleading"\n- "investigation found"\n\nthen preserve that language in the claim when it is central to the article.\n\nDo not quietly translate charged language into neutral language.\n\nInstead, extract separate claims when needed.\n\nExample:\n1. "Viewlands Elementary principal Frank Brouillet placed a second-grade boy in an enclosure known as ''the cage'' multiple times during the school day."\n2. "The enclosure known as ''the cage'' was used as a disciplinary seclusion space for a second-grade boy at Viewlands Elementary."\n3. "The second-grade boy at Viewlands Elementary was locked inside the enclosure known as ''the cage.''"\n4. "The second-grade boy at Viewlands Elementary was supervised while inside the enclosure known as ''the cage.''"\n5. "The enclosure known as ''the cage'' was located in or near a separate gym or basketball-court area at Viewlands Elementary."\n6. "Frank Brouillet’s handling of the second-grade boy violated Seattle Public Schools discipline or student safety policies."\n\nThese claims let later evidence search support, refute, or nuance each layer.\n\nSELF-CONTAINMENT REQUIREMENTS\n\nEach claim must:\n- Be a complete sentence.\n- Be falsifiable or evidence-checkable.\n- Include named entities from the text when available.\n- Include location or institution when available.\n- Include dates or time periods when available and relevant.\n- Preserve quoted terms and disputed labels.\n- Resolve pronouns.\n- Avoid vague words like "some," "officials," "critics," or "experts" when the text gives specific identities.\n- Reflect the text, not outside knowledge.\n\nAVOID\n\n- Generic claims that could apply to many places.\n- Claims without names when the article provides names.\n- Claims without locations when the article provides locations.\n- Claims that remove the key controversy.\n- Claims that summarize the article so broadly that source search becomes useless.\n- Over-sanitized claims that strip out charged terms central to the dispute.\n- Meta-claims about what the article says.\n- Over-fragmenting the main allegation into tiny context-free facts.\n- Extracting only bland institutional claims while missing the article’s central allegation.\n\nQUANTITY GUIDANCE\n\nReturn at least {{minClaims}} claims unless the text truly contains fewer verifiable claims.\n\nDo not stop early merely because 5 claims are strong.\n\nFor normal articles, aim for 7–10 claims when {{maxClaims}} allows it:\n- 1 central real-world thesis claim\n- 2–3 central event or allegation claims\n- 2–3 official finding or evidence claims\n- 1–2 framing or interpretive claims\n- remaining slots for important atomic details\n\nOnly approach {{maxClaims}} if the article contains genuinely distinct, important, verifiable claims.\n\nOUTPUT ORDER\n\nOrder claims by importance:\n1. Central real-world thesis or central allegation\n2. Core event claims\n3. Official findings or document-based claims\n4. Framing or interpretive claims\n5. Other important atomic evidence claims\n\nDo NOT invent topics or testimonials in this mode.', '"{\\"maxClaims\\": 12, \\"minClaims\\": 3}"', 6, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (1, 'claim_extraction_ranked_system', 'system', 'You are a precise claim extraction assistant. You must return strictly valid JSON.', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (405, 'claim_extraction_ranked_with_topics', 'user', 'TASKS\n\n1) Identify the single most general topic, max 2 words.\n2) List 2–5 specific subtopics under that topic.\n3) Extract {{minClaims}}-{{maxClaims}} IMPORTANT, VERIFIABLE claims from the text.\n4) Extract any testimonials or first-person case studies if present.\n\nPRIMARY GOAL\n\nExtract the most important real-world claims made in the text.\n\nDo NOT extract claims about the article itself.\n\nYour job is not to prove that the article said something.\nYour job is to extract the factual claims, allegations, findings, and interpretations that the article asks the reader to believe.\n\nCRITICAL DISTINCTION: EXTRACT WORLD-CLAIMS, NOT ARTICLE-CLAIMS\n\nDo NOT write claims in this form:\n- "The article says..."\n- "The article reports..."\n- "The author argues..."\n- "The text claims..."\n- "According to the article..."\n- "KUOW reports..."\n- "The article suggests..."\n\nUnless the attribution itself is the thing being fact-checked.\n\nInstead, convert article statements into direct, testable real-world claims.\n\nBAD:\n"The article reports that Viewlands Elementary principal Frank Brouillet placed a second-grade boy in an enclosure known as ''the cage'' multiple times during the school day."\n\nGOOD:\n"Viewlands Elementary principal Frank Brouillet placed a second-grade boy in an enclosure known as ''the cage'' multiple times during the school day."\n\nBAD:\n"The article argues that Seattle Public Schools failed to protect a student."\n\nGOOD:\n"Seattle Public Schools failed to protect a second-grade boy at Viewlands Elementary from repeated placement in an enclosure known as ''the cage.''"\n\nBAD:\n"KUOW says the enclosure was called ''the cage.''"\n\nGOOD:\n"An enclosure used for a second-grade boy at Viewlands Elementary was known as ''the cage.''"\n\nUse attribution only when the source of the claim is itself part of the real-world claim.\n\nGOOD:\n"Seattle Public Schools investigators found that a second-grade boy at Viewlands Elementary was placed in an enclosure known as ''the cage'' multiple times during the school day."\n\nARTICLE-SPECIFICITY REQUIREMENT\n\nThe output must NOT genericize the article.\n\nA good claim should preserve the article’s unique identifying details whenever present:\n- named people\n- named institutions\n- named schools, agencies, companies, courts, studies, reports, or organizations\n- city, state, country, or region\n- dates or time periods\n- quoted terms or disputed labels\n- specific actions\n- specific findings\n- specific allegations\n- specific conclusions\n- affected people or groups\n\nIf the article names a person, institution, place, report, study, agency, official, or organization, include those names in the relevant claims.\n\nIf the article uses a distinctive or contested phrase, preserve it in quotation marks.\n\nExamples of distinctive or contested phrases:\n- "the cage"\n- "locked in"\n- "seclusion"\n- "restraint"\n- "outside enclosure"\n- "investigation found"\n- "cleared of wrongdoing"\n- "policy violation"\n- "misleading"\n- "abuse"\n- "cover-up"\n\nDo NOT replace specific language with generic language.\n\nBAD:\n"A school district used controversial discipline practices."\n\nGOOD:\n"Viewlands Elementary principal Frank Brouillet placed a second-grade boy in an enclosure known as ''the cage'' multiple times during the school day."\n\nBAD:\n"An investigation found misconduct at a school."\n\nGOOD:\n"Seattle Public Schools investigators found that a second-grade boy at Viewlands Elementary was placed in an enclosure known as ''the cage'' multiple times during the school day."\n\nCLAIM SELECTION STRATEGY\n\nExtract a mix of these claim types, ranked by importance:\n\nA) CENTRAL REAL-WORLD THESIS CLAIM, REQUIRED AS FIRST CLAIM\n- The first claim must capture the article’s central factual allegation, finding, conclusion, or argument.\n- It must be a direct claim about reality, not a meta-claim about the article.\n- It must include the key named entities, locations, institutions, and distinctive wording when present.\n- It may synthesize the article’s main point, but it must remain specific, evidence-checkable, and searchable.\n\nB) CENTRAL EVENT OR ALLEGATION CLAIMS\n- Claims describing the central event, allegation, accusation, finding, or dispute.\n- Include who did what, to whom, where, when, and under what claimed circumstances.\n- Preserve charged or disputed language when it is central to the article.\n\nC) OFFICIAL FINDING OR DOCUMENT CLAIMS\n- Investigation findings\n- Court findings\n- Agency findings\n- School district findings\n- Police reports\n- Medical or scientific findings\n- Published study findings\n- Policy or disciplinary findings\n\nD) FRAMING OR INTERPRETIVE CLAIMS\n- Claims about whether an event constituted abuse, misconduct, negligence, exoneration, policy failure, institutional wrongdoing, discrimination, risk, or safety failure.\n- These are valid only when grounded in the text.\n- Phrase them as real-world claims, not as claims about the article’s framing.\n\nBAD:\n"The article frames the enclosure as a disciplinary seclusion space."\n\nGOOD:\n"The enclosure known as ''the cage'' functioned as a disciplinary seclusion space for the second-grade boy at Viewlands Elementary."\n\nE) ATOMIC SUPPORTING CLAIMS\n- Concrete details that can be verified independently.\n- Break compound statements into separate claims when doing so improves verification.\n- Preserve enough context so each claim stands alone.\n\nRANKING CRITERIA\n\nPrioritize in this order:\n\n1. Centrality: The claim is necessary to understand the article’s main point.\n2. Identifiability: The claim includes enough names, places, institutions, and wording to identify the same incident, report, study, or dispute.\n3. Controversy: The claim is disputed, high-stakes, surprising, reputationally significant, or central to the conflict.\n4. Falsifiability: The claim can be supported, refuted, or nuanced with evidence.\n5. Search usefulness: The claim would produce relevant search results instead of unrelated articles.\n6. Specificity: The claim contains concrete details where available.\n\nIMPORTANT: DO NOT CHOOSE BROADNESS OVER IDENTIFIABILITY\n\nA broader claim is only better if it still includes the specific people, institutions, locations, and disputed wording needed to identify the article.\n\nBAD BROAD THESIS:\n"School discipline policies can harm vulnerable students."\n\nGOOD ARTICLE-SPECIFIC THESIS:\n"Seattle Public Schools failed to protect a second-grade boy at Viewlands Elementary from repeated placement in an enclosure known as ''the cage.''"\n\nPRESERVE CHARGED OR CONTESTED LANGUAGE\n\nIf the text uses charged language such as:\n- "locked in a cage"\n- "the cage"\n- "abuse"\n- "seclusion"\n- "restraint"\n- "cover-up"\n- "exonerated"\n- "falsely accused"\n- "misleading"\n- "investigation found"\n\nthen preserve that language in the claim when it is central to the article.\n\nDo not quietly translate charged language into neutral language.\n\nInstead, extract separate claims when needed.\n\nExample:\n1. "Viewlands Elementary principal Frank Brouillet placed a second-grade boy in an enclosure known as ''the cage'' multiple times during the school day."\n2. "The enclosure known as ''the cage'' was used as a disciplinary seclusion space for a second-grade boy at Viewlands Elementary."\n3. "The second-grade boy at Viewlands Elementary was locked inside the enclosure known as ''the cage.''"\n4. "The second-grade boy at Viewlands Elementary was supervised while inside the enclosure known as ''the cage.''"\n5. "The enclosure known as ''the cage'' was located in or near a separate gym or basketball-court area at Viewlands Elementary."\n6. "Frank Brouillet’s handling of the second-grade boy violated Seattle Public Schools discipline or student safety policies."\n\nThese claims let later evidence search support, refute, or nuance each layer.\n\nSELF-CONTAINMENT REQUIREMENTS\n\nEach claim must:\n- Be a complete sentence.\n- Be falsifiable or evidence-checkable.\n- Include named entities from the text when available.\n- Include location or institution when available.\n- Include dates or time periods when available and relevant.\n- Preserve quoted terms and disputed labels.\n- Resolve pronouns.\n- Avoid vague words like "some," "officials," "critics," or "experts" when the text gives specific identities.\n- Reflect the text, not outside knowledge.\n\nAVOID\n\n- Generic claims that could apply to many places.\n- Claims without names when the article provides names.\n- Claims without locations when the article provides locations.\n- Claims that remove the key controversy.\n- Claims that summarize the article so broadly that source search becomes useless.\n- Over-sanitized claims that strip out charged terms central to the dispute.\n- Meta-claims about what the article says.\n- Over-fragmenting the main allegation into tiny context-free facts.\n- Extracting only bland institutional claims while missing the article’s central allegation.\n\nQUANTITY GUIDANCE\n\nReturn at least {{minClaims}} claims unless the text truly contains fewer verifiable claims.\n\nDo not stop early merely because 5 claims are strong.\n\nFor normal articles, aim for 7–10 claims when {{maxClaims}} allows it:\n- 1 central real-world thesis claim\n- 2–3 central event or allegation claims\n- 2–3 official finding or evidence claims\n- 1–2 framing or interpretive claims\n- remaining slots for important atomic details\n\nOnly approach {{maxClaims}} if the article contains genuinely distinct, important, verifiable claims.\n\nOUTPUT ORDER\n\nOrder claims by importance:\n1. Central real-world thesis or central allegation\n2. Core event claims\n3. Official findings or document-based claims\n4. Framing or interpretive claims\n5. Other important atomic evidence claims\n\nTESTIMONIAL EXTRACTION\n\nExtract any testimonials or first-person case studies if present as objects with:\n- "text"\n- optional "name"\n- optional "imageUrl"\n\nDo not invent topics, subtopics, claims, or testimonials.', '{"max_claims": 9}', 6, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (6, 'claim_filtering', 'user', 'Evaluate this claim for verification worthiness:\n\nCLAIM: "{{claim}}"\n\nRate 0.0-1.0 on each dimension:\n\n1. SPECIFICITY: Is this specific and falsifiable? (NOT vague like "there was a study")\n   - 1.0 = Concrete, verifiable assertion with specifics (numbers, dates, names)\n   - 0.5 = Somewhat specific but missing key details\n   - 0.0 = Vague, generic, or subjective opinion\n\n2. CONTROVERSY: Would reasonable people dispute this? Is it worth checking?\n   - 1.0 = Genuinely controversial or surprising claim\n   - 0.5 = Somewhat debatable\n   - 0.0 = Obviously true/false or trivial\n\n3. MATERIALITY: Is this central to the article''s main argument?\n   - 1.0 = Core thesis or key supporting claim\n   - 0.5 = Supporting detail\n   - 0.0 = Background context or filler\n\nReturn JSON: {"specificity": X, "controversy": Y, "materiality": Z, "reasoning": "brief explanation"}', '{"threshold":0.6}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (109, 'claim_matching_system', 'system', 'You are a fact-checking assistant that analyzes how reference claims relate to task claims.\n\nFor each reference claim, determine:\n1. Which task claim(s) it addresses (if any)\n2. The stance: support, refute, nuance, or insufficient\n3. Veracity score (0-1): How truthful/reliable is this reference claim?\n   - 0.9-1.0: Highly verified, strong evidence\n   - 0.7-0.89: Well-supported, credible sources\n   - 0.5-0.69: Moderate support, some evidence\n   - 0.3-0.49: Weak support, limited evidence\n   - 0.0-0.29: Unverified, questionable, or contradicted\n4. Confidence (0.15-0.98): How confident are you in this match?\n5. Support level (-1.2 to +1.2): Directional strength\n   - Positive: supports the task claim\n   - Negative: refutes the task claim\n   - Magnitude: strength of support/refutation\n\nReturn ONLY matches where the reference claim meaningfully addresses a task claim.', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (110, 'claim_matching_user', 'user', 'TASK CLAIMS (what we''re fact-checking):\n{{taskClaims}}\n\nREFERENCE CLAIMS (from evidence source):\n{{referenceClaims}}\n\nFor each reference claim that addresses a task claim, return a match object.\nONLY include matches where there''s a clear relationship.\n\nReturn JSON array of matches:\n[\n  {\n    "task_claim_index": 0-based index,\n    "reference_claim_index": 0-based index,\n    "stance": "support|refute|nuance|insufficient",\n    "veracity": 0.0-1.0,\n    "confidence": 0.15-0.98,\n    "support_level": -1.2 to +1.2,\n    "reasoning": "brief explanation"\n  }\n]', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (107, 'claim_properties_evaluation_system', 'system', 'You are a claim property evaluator. Return only valid JSON with scores 0.00-1.00.', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (108, 'claim_properties_evaluation_user', 'user', 'Evaluate this claim across multiple dimensions. Score each 0.00-1.00.\n\nCLAIM: "{{claim_text}}"\n\nSOURCE DOCUMENT PREVIEW (first 1500 chars):\n{{source_document_preview}}\n\nSCORE EACH DIMENSION (0.00-1.00):\n\n1. claim_centrality: How central is this claim to the source document''s argument?\n   1.00 = Core thesis or primary claim\n   0.50 = Important supporting claim\n   0.00 = Tangential mention or background\n\n2. claim_specificity: How specific and falsifiable is this claim?\n   1.00 = Concrete, specific, includes numbers/dates/names\n   0.50 = Somewhat specific but vague details\n   0.00 = Vague, generic, subjective opinion\n\n3. claim_consequence: What are the real-world stakes of this claim?\n   1.00 = High consequence (public health, major policy, safety)\n   0.50 = Moderate consequence (personal decisions, local impact)\n   0.00 = Low consequence (trivial, low-stakes)\n\n4. claim_contestability: Would reasonable people dispute this claim?\n   1.00 = Highly contested, significant disagreement\n   0.50 = Some debate, mixed evidence\n   0.00 = Widely accepted fact or obvious statement\n\n5. claim_novelty: Is this a novel/obscure/fringe assertion?\n   1.00 = Novel, unusual, rarely discussed\n   0.50 = Somewhat novel, emerging discussion\n   0.00 = Well-known, commonly discussed\n\nReturn JSON:\n{\n  "claim_centrality": 0.00-1.00,\n  "claim_specificity": 0.00-1.00,\n  "claim_consequence": 0.00-1.00,\n  "claim_contestability": 0.00-1.00,\n  "claim_novelty": 0.00-1.00,\n  "reasoning": "brief explanation"\n}', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (111, 'claim_relevance_assessment_system', 'system', 'You are assessing whether a reference claim is relevant to a task claim.\n\nGuidelines:\n- "support": Reference claim provides evidence FOR the task claim\n- "refute": Reference claim provides evidence AGAINST the task claim\n- "nuance": Reference claim adds context or partial support/refutation\n- "insufficient": Reference claim is not relevant or doesn''t provide meaningful evidence\n\n- confidence: 0-1 (how certain you are of the stance)\n- quality: 0-1.2 (how strong/useful the reference claim is as evidence)\n- rationale: 1-2 sentences explaining WHY this stance applies', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (112, 'claim_relevance_assessment_user', 'user', 'TASK CLAIM:\n"{{taskClaimText}}"\n\nREFERENCE CLAIM:\n"{{referenceClaimText}}"\n\nAnalyze whether the reference claim supports, refutes, nuances, or is insufficient for evaluating the task claim.{{customInstructions}}\n\nReturn JSON:\n{\n  "stance": "support|refute|nuance|insufficient",\n  "confidence": 0.0-1.0,\n  "quality": 0.0-1.2,\n  "rationale": "brief explanation"\n}', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (300, 'claim_triage_system', 'system', 'You are a fact-checking triage specialist. You determine which claims are checkable and prioritize them for verification.', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (301, 'claim_triage_user', 'user', 'Analyze this claim for fact-checking triage:\n\nClaim: {{claim_text}}\nContext: {{context}}\n\nDetermine:\n1. **Checkability**: Can this claim be verified with evidence? (checkable/opinion/too_vague/prediction)\n2. **Priority**: How important is it to check this claim? (high/medium/low)\n3. **Complexity**: How difficult will it be to fact-check? (simple/moderate/complex)\n4. **Required Evidence Types**: What types of sources would be needed?\n\nClassify and provide reasoning.', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (400, 'evidence_assessment_system', 'system', 'You are a critical thinking expert who evaluates how well evidence supports or refutes claims. You assess relevance, strength, and stance.', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (401, 'evidence_assessment_user', 'user', 'Evaluate how this evidence relates to the claim:\n\nClaim: {{claim_text}}\nEvidence Source: {{source_name}}\nEvidence Text: {{evidence_text}}\n\nAssess:\n1. **Stance**: Does this evidence support, refute, or provide nuance to the claim?\n2. **Strength**: How strong is this evidence? (0-100)\n3. **Relevance**: How relevant is this evidence? (0-100)\n4. **Support Level**: Overall support level (-1.0 to +1.0, where -1 strongly refutes, 0 is neutral/irrelevant, +1 strongly supports)\n\nProvide your assessment with reasoning.', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (100, 'evidence_query_generation_system', 'system', 'You generate diverse, high-precision search queries for fact-checking. CRITICAL: You must create queries designed to find sources that SUPPORT, REFUTE, and provide NUANCED perspectives on the claim.', '{}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (101, 'evidence_query_generation_user', 'user', 'Claim: {{claimText}}\nContext: {{context}}\n\nTask: Produce {{n}} queries across intents with the following distribution:\n- At least 2 queries designed to find sources that SUPPORT the claim (prefer 3)\n- At least 2 queries designed to find sources that REFUTE the claim (prefer 3)\n- At least 1 query designed to find sources that provide NUANCED perspective on the claim (prefer 3)\n- The remaining queries can cover background or factbox information\n\nIMPORTANT: Design your queries to actively seek out sources with different perspectives. For refute queries, look for credible counterarguments, debunking sites, fact-checks, or alternative evidence. For support queries, look for sources that would confirm or provide evidence for the claim. For nuance queries, look for sources that provide context, caveats, or partial support/refutation.', '{"n":6}', 1, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (404, 'evidence_query_generation_user_balanced', 'user', '  CLAIM TO VERIFY:\n  "{{claimText}}"\n\n  CONTEXT:\n  {{context}}\n\n  TASK: Generate EXACTLY {{n}} diverse search queries to find evidence for\n  this claim.\n\n  BALANCED DISTRIBUTION REQUIRED:\n  - {{supportQueries}} queries designed to find sources that SUPPORT the\n  claim\n  - {{refuteQueries}} queries designed to find sources that REFUTE the\n  claim\n  - {{nuanceQueries}} queries designed to find sources that provide NUANCED\n   perspective\n\n  QUERY DESIGN GUIDELINES:\n\n  For SUPPORT queries:\n  - Search for confirmatory evidence, corroboration, similar findings\n  - Target academic studies, expert statements, authoritative sources\n  - Examples: "evidence supporting [claim]", "studies confirming [claim]",\n  "[claim] research"\n\n  For REFUTE queries:\n  - Search for debunking, fact-checks, counterarguments, contradictory\n  evidence\n  - Target fact-checkers, critical analyses, alternative interpretations\n  - Examples: "debunking [claim]", "fact-check [claim]", "[claim] false",\n  "[claim] myth"\n\n  For NUANCE queries:\n  - Search for context, caveats, limitations, partial agreements,\n  complexities\n  - Target analysis pieces, expert discussions, contextual information\n  - Examples: "[claim] context", "[claim] limitations", "[claim] nuance",\n  "complexity of [claim]"\n\n  CRITICAL: Ensure queries actively seek OPPOSING viewpoints, not just\n  variations of one perspective.\n\n  OUTPUT FORMAT:\n  Return EXACTLY {{n}} queries as a JSON array of strings.\n\n  Example: ["evidence supporting claim X", "studies confirming X", "X\n  research", "debunking X", "fact-check X", "X false", "context for X",\n  "limitations of X", "nuance in X"]', '{"n": 6}', 2, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (114, 'source_quality_evaluation_system', 'system', 'You are a source quality evaluator. Return only valid JSON with scores 0-10.', '{}', 2, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
INSERT INTO llm_prompts (prompt_id, prompt_name, prompt_type, prompt_text, parameters, version, is_active, max_claims, min_sources, max_sources) VALUES (113, 'source_quality_evaluation_user', 'user', 'Evaluate this source across multiple quality dimensions. Score each 0-10.\n\nSOURCE METADATA:\n- URL: {{url}}\n- Domain: {{domain}}\n- Author: {{author}}\n- Publisher: {{publisher}}\n- Date: {{date}}\n{{citationInfo}}\n\nCONTENT PREVIEW (first 2000 chars):\n{{contentPreview}}\n\nSCORE EACH DIMENSION (0-10 scale):\n\nTRANSPARENCY:\n1. author_transparency: Named author with credentials and traceable identity?\n   10 = Named expert with verifiable credentials\n   5 = Named author, unclear credentials\n   0 = Anonymous or pseudonymous\n\n2. publisher_transparency: Clear about page, editorial standards, ownership?\n   10 = Major publication with clear standards\n   5 = Some transparency, unclear ownership\n   0 = No transparency, hidden ownership\n\nEVIDENCE QUALITY:\n3. evidence_density: Citations, documents, data, primary source quotations?\n   {{citationNote}}\n   10 = Extensive citations and primary sources (15+ citations)\n   5 = Some evidence, limited citations (3-10 citations)\n   0 = Opinion without evidence (0-2 citations)\n\n4. claim_specificity: Concrete testable claims vs vague rhetoric?\n   10 = Specific, falsifiable claims with details\n   5 = Mix of specific and vague\n   0 = All vague assertions\n\nRELIABILITY:\n5. correction_behavior: Corrections/updates visible in this content?\n   10 = Clear corrections/updates visible\n   5 = Some corrections visible\n   0 = No corrections visible\n\nORIGINALITY:\n6. original_reporting: Firsthand reporting vs recycled assertions?\n   10 = Original investigative reporting\n   5 = Mix of original and aggregated\n   0 = All recycled content, no original work\n\nRISK INDICATORS (higher = riskier):\n7. sensationalism_score: Emotional framing, certainty inflation, outrage bait?\n   10 = Extreme sensationalism, all-caps, outrage maximization\n   5 = Some emotional language, moderate framing\n   0 = Neutral, measured tone\n\n8. monetization_pressure: Visible signs of aggressive monetization?\n   10 = Heavy affiliate links, clickbait structure\n   5 = Some promotional content\n   0 = Minimal commercial pressure evident\n\nReturn JSON:\n{\n  "author_transparency": 0-10,\n  "publisher_transparency": 0-10,\n  "evidence_density": 0-10,\n  "claim_specificity": 0-10,\n  "correction_behavior": 0-10,\n  "original_reporting": 0-10,\n  "sensationalism_score": 0-10,\n  "monetization_pressure": 0-10,\n  "reasoning": "brief explanation"\n}', '{}', 2, 1, 12, 2, 4) ON DUPLICATE KEY UPDATE prompt_name=VALUES(prompt_name), prompt_type=VALUES(prompt_type), prompt_text=VALUES(prompt_text), parameters=VALUES(parameters), version=VALUES(version), is_active=VALUES(is_active), max_claims=VALUES(max_claims), min_sources=VALUES(min_sources), max_sources=VALUES(max_sources);
